#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        long long cur = 0;
        for (int i = 0; i < n; ++i) {
            int x;
            scanf("%d", &x);
            cur += x;
            printf("%lld", cur);
            if (i + 1 < n) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

